DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'users' AND column_name = 'role') THEN
        INSERT INTO user_roles (user_id, role)
        SELECT id, role FROM users WHERE role IS NOT NULL;
    END IF;
END $$;


DO $$
BEGIN
    -- Drop the check constraint if it exists
    IF EXISTS (SELECT 1 FROM information_schema.table_constraints WHERE table_name = 'users' AND constraint_name = 'users_role_check') THEN
        ALTER TABLE users DROP CONSTRAINT users_role_check;
    END IF;
    -- Drop the index if it exists
    IF EXISTS (SELECT 1 FROM pg_indexes WHERE tablename = 'users' AND indexname = 'ix_users_role') THEN
        DROP INDEX IF EXISTS ix_users_role;
    END IF;
    -- Drop the column if it exists
    IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'users' AND column_name = 'role') THEN
        ALTER TABLE users DROP COLUMN role;
    END IF;
END $$;
